"""
s01: The Agent Loop — 最小同步对话循环

这是 Hermes Agent 教学系列的第一个可运行实现。
它只做一件事：发给模型 → 处理工具调用 → 结果回写 → 继续。

运行:
    export OPENAI_API_KEY=sk-xxx
    python agents/s01_agent_loop.py

默认用 OpenRouter，也可以设 OPENAI_BASE_URL 指向其他 OpenAI 兼容端点。
"""

import json
import os
import subprocess

from openai import OpenAI

# ---------------------------------------------------------------------------
# 配置
# ---------------------------------------------------------------------------

BASE_URL = os.getenv("OPENAI_BASE_URL", "https://openrouter.ai/api/v1")
API_KEY = os.getenv("OPENAI_API_KEY", "")
MODEL = os.getenv("MODEL", "anthropic/claude-sonnet-4")
MAX_ITERATIONS = int(os.getenv("MAX_ITERATIONS", "30"))

client = OpenAI(base_url=BASE_URL, api_key=API_KEY)

SYSTEM_PROMPT = "You are a helpful assistant. You can run shell commands via the terminal tool."

# ---------------------------------------------------------------------------
# 工具定义（只有一个：终端命令执行）
# ---------------------------------------------------------------------------

TOOLS = [
    {
        "type": "function",
        "function": {
            "name": "terminal",
            "description": "Run a shell command and return its output.",
            "parameters": {
                "type": "object",
                "properties": {
                    "command": {
                        "type": "string",
                        "description": "The shell command to execute",
                    }
                },
                "required": ["command"],
            },
        },
    }
]

# ---------------------------------------------------------------------------
# 工具执行
# ---------------------------------------------------------------------------

BLOCKED_COMMANDS = ["rm -rf /", "mkfs", "dd if=", "shutdown", "reboot"]


def run_tool(name: str, arguments: str) -> str:
    args = json.loads(arguments)

    if name == "terminal":
        command = args.get("command", "")
        for blocked in BLOCKED_COMMANDS:
            if blocked in command:
                return json.dumps({"error": f"Blocked: {blocked}"})
        try:
            result = subprocess.run(
                command, shell=True, capture_output=True, text=True, timeout=30
            )
            output = result.stdout + result.stderr
            return output[:10000] if output else "(no output)"
        except subprocess.TimeoutExpired:
            return "(command timed out after 30s)"
        except Exception as e:
            return f"(error: {e})"

    return json.dumps({"error": f"Unknown tool: {name}"})


# ---------------------------------------------------------------------------
# 核心循环
# ---------------------------------------------------------------------------


def run_conversation(user_message: str) -> dict:
    """
    同步对话循环。
    接收用户消息 → 反复调模型和工具 → 直到模型不再调工具 → 返回最终回复。
    """
    messages = [{"role": "user", "content": user_message}]

    for iteration in range(MAX_ITERATIONS):
        # 组装 API 调用
        api_messages = [{"role": "system", "content": SYSTEM_PROMPT}] + messages

        response = client.chat.completions.create(
            model=MODEL,
            messages=api_messages,
            tools=TOOLS,
        )

        assistant_msg = response.choices[0].message

        # 把 assistant 回复写进 messages
        msg_dict: dict = {
            "role": "assistant",
            "content": assistant_msg.content or "",
        }
        if assistant_msg.tool_calls:
            msg_dict["tool_calls"] = [
                {
                    "id": tc.id,
                    "type": "function",
                    "function": {
                        "name": tc.function.name,
                        "arguments": tc.function.arguments,
                    },
                }
                for tc in assistant_msg.tool_calls
            ]
        messages.append(msg_dict)

        # 没有 tool_calls → 对话结束
        if not assistant_msg.tool_calls:
            return {"final_response": assistant_msg.content, "messages": messages}

        # 执行每个工具，把结果写回 messages
        for tool_call in assistant_msg.tool_calls:
            print(f"  🔧 {tool_call.function.name}: {tool_call.function.arguments}")
            output = run_tool(tool_call.function.name, tool_call.function.arguments)
            messages.append(
                {
                    "role": "tool",
                    "tool_call_id": tool_call.id,
                    "content": output,
                }
            )

    return {"final_response": "(max iterations reached)", "messages": messages}


# ---------------------------------------------------------------------------
# 入口
# ---------------------------------------------------------------------------

if __name__ == "__main__":
    print("=== s01: Minimal Agent Loop ===")
    print(f"Model: {MODEL}")
    print(f"Base URL: {BASE_URL}")
    print("Type 'quit' to exit.\n")

    while True:
        user_input = input("You: ").strip()
        if not user_input or user_input.lower() in ("quit", "exit"):
            break

        result = run_conversation(user_input)
        print(f"\nAssistant: {result['final_response']}\n")

"""
s02: Tool System — 自注册工具系统

在 s01 基础上加入：
- ToolRegistry：工具注册表（工具自己注册自己）
- 多工具：terminal + read_file + write_file + web_search(桩)
- dispatch 分发：注册表查表执行，循环不变

运行:
    export OPENAI_API_KEY=sk-xxx
    python agents/s02_tool_system.py
"""

import json
import os
import subprocess
from dataclasses import dataclass, field
from typing import Callable, Optional

from openai import OpenAI

# ---------------------------------------------------------------------------
# 配置
# ---------------------------------------------------------------------------

BASE_URL = os.getenv("OPENAI_BASE_URL", "https://openrouter.ai/api/v1")
API_KEY = os.getenv("OPENAI_API_KEY", "")
MODEL = os.getenv("MODEL", "anthropic/claude-sonnet-4")
MAX_ITERATIONS = int(os.getenv("MAX_ITERATIONS", "30"))

client = OpenAI(base_url=BASE_URL, api_key=API_KEY)

SYSTEM_PROMPT = (
    "You are a helpful assistant. "
    "You can run shell commands, read/write files, and search the web."
)

# ---------------------------------------------------------------------------
# 工具注册表
# ---------------------------------------------------------------------------


@dataclass
class ToolEntry:
    name: str
    toolset: str
    schema: dict
    handler: Callable
    is_async: bool = False
    requires_env: list = field(default_factory=list)
    check_fn: Optional[Callable] = None


class ToolRegistry:
    def __init__(self):
        self._tools: dict[str, ToolEntry] = {}

    def register(self, name: str, toolset: str, schema: dict, handler: Callable, **kwargs):
        self._tools[name] = ToolEntry(
            name=name, toolset=toolset, schema=schema, handler=handler, **kwargs
        )

    def dispatch(self, name: str, args: dict, **kwargs) -> str:
        entry = self._tools.get(name)
        if not entry:
            return json.dumps({"error": f"Unknown tool: {name}"})
        return entry.handler(args, **kwargs)

    def get_definitions(self, enabled_toolsets: list[str] | None = None) -> list[dict]:
        defs = []
        for entry in self._tools.values():
            if enabled_toolsets and entry.toolset not in enabled_toolsets:
                continue
            if entry.check_fn and not entry.check_fn():
                continue
            defs.append(
                {"type": "function", "function": entry.schema}
            )
        return defs


registry = ToolRegistry()

# ---------------------------------------------------------------------------
# 工具实现（每个工具自注册）
# ---------------------------------------------------------------------------

BLOCKED_COMMANDS = ["rm -rf /", "mkfs", "dd if=", "shutdown", "reboot"]


def handle_terminal(args, **kwargs):
    command = args.get("command", "")
    for blocked in BLOCKED_COMMANDS:
        if blocked in command:
            return json.dumps({"error": f"Blocked: {blocked}"})
    try:
        result = subprocess.run(
            command, shell=True, capture_output=True, text=True, timeout=30
        )
        output = result.stdout + result.stderr
        return output[:10000] if output else "(no output)"
    except subprocess.TimeoutExpired:
        return "(command timed out after 30s)"
    except Exception as e:
        return f"(error: {e})"


registry.register(
    name="terminal",
    toolset="terminal",
    schema={
        "name": "terminal",
        "description": "Run a shell command and return its output.",
        "parameters": {
            "type": "object",
            "properties": {"command": {"type": "string", "description": "Shell command"}},
            "required": ["command"],
        },
    },
    handler=handle_terminal,
)


def handle_read_file(args, **kwargs):
    path = args.get("path", "")
    try:
        with open(path, "r", encoding="utf-8") as f:
            content = f.read(100_000)
        return content if content else "(empty file)"
    except Exception as e:
        return f"(error: {e})"


registry.register(
    name="read_file",
    toolset="file",
    schema={
        "name": "read_file",
        "description": "Read a file and return its contents.",
        "parameters": {
            "type": "object",
            "properties": {"path": {"type": "string", "description": "File path"}},
            "required": ["path"],
        },
    },
    handler=handle_read_file,
)


def handle_write_file(args, **kwargs):
    path = args.get("path", "")
    content = args.get("content", "")
    try:
        os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
        with open(path, "w", encoding="utf-8") as f:
            f.write(content)
        return f"Written {len(content)} chars to {path}"
    except Exception as e:
        return f"(error: {e})"


registry.register(
    name="write_file",
    toolset="file",
    schema={
        "name": "write_file",
        "description": "Write content to a file.",
        "parameters": {
            "type": "object",
            "properties": {
                "path": {"type": "string", "description": "File path"},
                "content": {"type": "string", "description": "Content to write"},
            },
            "required": ["path", "content"],
        },
    },
    handler=handle_write_file,
)


def handle_web_search(args, **kwargs):
    query = args.get("query", "")
    return json.dumps({"note": "web_search is a stub in this teaching version", "query": query})


registry.register(
    name="web_search",
    toolset="web",
    schema={
        "name": "web_search",
        "description": "Search the web for information.",
        "parameters": {
            "type": "object",
            "properties": {"query": {"type": "string", "description": "Search query"}},
            "required": ["query"],
        },
    },
    handler=handle_web_search,
)

# ---------------------------------------------------------------------------
# 核心循环（和 s01 相同，只是工具来源换成了注册表）
# ---------------------------------------------------------------------------

ENABLED_TOOLSETS = ["terminal", "file", "web"]


def run_conversation(user_message: str) -> dict:
    messages = [{"role": "user", "content": user_message}]
    tools = registry.get_definitions(ENABLED_TOOLSETS)

    for iteration in range(MAX_ITERATIONS):
        api_messages = [{"role": "system", "content": SYSTEM_PROMPT}] + messages

        response = client.chat.completions.create(
            model=MODEL, messages=api_messages, tools=tools
        )

        assistant_msg = response.choices[0].message

        msg_dict: dict = {"role": "assistant", "content": assistant_msg.content or ""}
        if assistant_msg.tool_calls:
            msg_dict["tool_calls"] = [
                {
                    "id": tc.id,
                    "type": "function",
                    "function": {"name": tc.function.name, "arguments": tc.function.arguments},
                }
                for tc in assistant_msg.tool_calls
            ]
        messages.append(msg_dict)

        if not assistant_msg.tool_calls:
            return {"final_response": assistant_msg.content, "messages": messages}

        for tool_call in assistant_msg.tool_calls:
            name = tool_call.function.name
            args = json.loads(tool_call.function.arguments)
            print(f"  🔧 {name}: {json.dumps(args, ensure_ascii=False)[:120]}")
            output = registry.dispatch(name, args)
            messages.append({"role": "tool", "tool_call_id": tool_call.id, "content": output})

    return {"final_response": "(max iterations reached)", "messages": messages}


# ---------------------------------------------------------------------------
# 入口
# ---------------------------------------------------------------------------

if __name__ == "__main__":
    print("=== s02: Tool System ===")
    print(f"Model: {MODEL}")
    tools = registry.get_definitions(ENABLED_TOOLSETS)
    print(f"Tools: {[t['function']['name'] for t in tools]}")
    print("Type 'quit' to exit.\n")

    while True:
        user_input = input("You: ").strip()
        if not user_input or user_input.lower() in ("quit", "exit"):
            break
        result = run_conversation(user_input)
        print(f"\nAssistant: {result['final_response']}\n")

"""
s03: Session Store — SQLite 持久化

在 s02 基础上加入：
- SQLite + WAL 模式存储会话和消息
- 重启后可恢复历史对话
- 基本的 FTS5 全文搜索

运行:
    export OPENAI_API_KEY=sk-xxx
    python agents/s03_session_store.py
"""

import json
import os
import sqlite3
import subprocess
import time
import uuid
from dataclasses import dataclass, field
from typing import Callable, Optional

from openai import OpenAI

# ---------------------------------------------------------------------------
# 配置
# ---------------------------------------------------------------------------

BASE_URL = os.getenv("OPENAI_BASE_URL", "https://openrouter.ai/api/v1")
API_KEY = os.getenv("OPENAI_API_KEY", "")
MODEL = os.getenv("MODEL", "anthropic/claude-sonnet-4")
MAX_ITERATIONS = int(os.getenv("MAX_ITERATIONS", "30"))
DB_PATH = os.getenv("DB_PATH", "state.db")

client = OpenAI(base_url=BASE_URL, api_key=API_KEY)

SYSTEM_PROMPT = (
    "You are a helpful assistant. "
    "You can run shell commands, read/write files, and search the web. "
    "Your conversations are persisted to SQLite."
)

# ---------------------------------------------------------------------------
# 工具注册表（复用 s02）
# ---------------------------------------------------------------------------


@dataclass
class ToolEntry:
    name: str
    toolset: str
    schema: dict
    handler: Callable
    is_async: bool = False
    requires_env: list = field(default_factory=list)
    check_fn: Optional[Callable] = None


class ToolRegistry:
    def __init__(self):
        self._tools: dict[str, ToolEntry] = {}

    def register(self, name, toolset, schema, handler, **kwargs):
        self._tools[name] = ToolEntry(name=name, toolset=toolset, schema=schema, handler=handler, **kwargs)

    def dispatch(self, name, args, **kwargs):
        entry = self._tools.get(name)
        if not entry:
            return json.dumps({"error": f"Unknown tool: {name}"})
        return entry.handler(args, **kwargs)

    def get_definitions(self, enabled_toolsets=None):
        defs = []
        for entry in self._tools.values():
            if enabled_toolsets and entry.toolset not in enabled_toolsets:
                continue
            defs.append({"type": "function", "function": entry.schema})
        return defs


registry = ToolRegistry()

# --- 工具实现 ---

def handle_terminal(args, **kwargs):
    command = args.get("command", "")
    for blocked in ["rm -rf /", "mkfs", "dd if=", "shutdown"]:
        if blocked in command:
            return json.dumps({"error": f"Blocked: {blocked}"})
    try:
        result = subprocess.run(command, shell=True, capture_output=True, text=True, timeout=30)
        output = result.stdout + result.stderr
        return output[:10000] if output else "(no output)"
    except subprocess.TimeoutExpired:
        return "(timed out)"
    except Exception as e:
        return f"(error: {e})"

registry.register("terminal", "terminal", {
    "name": "terminal", "description": "Run a shell command.",
    "parameters": {"type": "object", "properties": {"command": {"type": "string"}}, "required": ["command"]},
}, handle_terminal)

def handle_read_file(args, **kwargs):
    try:
        with open(args["path"], "r", encoding="utf-8") as f:
            return f.read(100_000) or "(empty)"
    except Exception as e:
        return f"(error: {e})"

registry.register("read_file", "file", {
    "name": "read_file", "description": "Read a file.",
    "parameters": {"type": "object", "properties": {"path": {"type": "string"}}, "required": ["path"]},
}, handle_read_file)

def handle_write_file(args, **kwargs):
    try:
        os.makedirs(os.path.dirname(args["path"]) or ".", exist_ok=True)
        with open(args["path"], "w", encoding="utf-8") as f:
            f.write(args["content"])
        return f"Written {len(args['content'])} chars"
    except Exception as e:
        return f"(error: {e})"

registry.register("write_file", "file", {
    "name": "write_file", "description": "Write content to a file.",
    "parameters": {"type": "object", "properties": {"path": {"type": "string"}, "content": {"type": "string"}}, "required": ["path", "content"]},
}, handle_write_file)

# ---------------------------------------------------------------------------
# SQLite 会话持久化（本章新增）
# ---------------------------------------------------------------------------


def init_db(db_path: str) -> sqlite3.Connection:
    conn = sqlite3.connect(db_path)
    conn.execute("PRAGMA journal_mode=WAL")
    conn.executescript("""
        CREATE TABLE IF NOT EXISTS sessions (
            id TEXT PRIMARY KEY,
            source TEXT NOT NULL,
            model TEXT,
            started_at REAL NOT NULL
        );
        CREATE TABLE IF NOT EXISTS messages (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            session_id TEXT NOT NULL REFERENCES sessions(id),
            role TEXT NOT NULL,
            content TEXT,
            tool_calls TEXT,
            tool_call_id TEXT,
            timestamp REAL NOT NULL
        );
        CREATE VIRTUAL TABLE IF NOT EXISTS messages_fts USING fts5(
            content, content=messages, content_rowid=id
        );
        CREATE TRIGGER IF NOT EXISTS messages_ai AFTER INSERT ON messages BEGIN
            INSERT INTO messages_fts(rowid, content) VALUES (new.id, new.content);
        END;
    """)
    return conn


def create_session(conn: sqlite3.Connection, source: str = "cli") -> str:
    session_id = str(uuid.uuid4())
    conn.execute(
        "INSERT INTO sessions (id, source, model, started_at) VALUES (?, ?, ?, ?)",
        (session_id, source, MODEL, time.time()),
    )
    conn.commit()
    return session_id


def add_message(conn: sqlite3.Connection, session_id: str, msg: dict):
    conn.execute(
        "INSERT INTO messages (session_id, role, content, tool_calls, tool_call_id, timestamp) VALUES (?, ?, ?, ?, ?, ?)",
        (
            session_id,
            msg["role"],
            msg.get("content", ""),
            json.dumps(msg.get("tool_calls")) if msg.get("tool_calls") else None,
            msg.get("tool_call_id"),
            time.time(),
        ),
    )
    conn.commit()


def get_session_messages(conn: sqlite3.Connection, session_id: str) -> list[dict]:
    rows = conn.execute(
        "SELECT role, content, tool_calls, tool_call_id FROM messages WHERE session_id = ? ORDER BY id",
        (session_id,),
    ).fetchall()
    messages = []
    for role, content, tool_calls_json, tool_call_id in rows:
        msg: dict = {"role": role, "content": content or ""}
        if tool_calls_json:
            msg["tool_calls"] = json.loads(tool_calls_json)
        if tool_call_id:
            msg["tool_call_id"] = tool_call_id
        messages.append(msg)
    return messages


def search_sessions(conn: sqlite3.Connection, query: str) -> list[dict]:
    rows = conn.execute(
        "SELECT m.session_id, m.content FROM messages_fts f JOIN messages m ON f.rowid = m.id WHERE f.content MATCH ? LIMIT 10",
        (query,),
    ).fetchall()
    return [{"session_id": r[0], "snippet": r[1][:200]} for r in rows]


# ---------------------------------------------------------------------------
# 核心循环（s01/s02 + 持久化）
# ---------------------------------------------------------------------------

ENABLED_TOOLSETS = ["terminal", "file"]


def run_conversation(user_message: str, conn: sqlite3.Connection, session_id: str) -> dict:
    # 从数据库恢复历史
    messages = get_session_messages(conn, session_id)

    # 追加新用户消息
    user_msg = {"role": "user", "content": user_message}
    messages.append(user_msg)
    add_message(conn, session_id, user_msg)

    tools = registry.get_definitions(ENABLED_TOOLSETS)

    for iteration in range(MAX_ITERATIONS):
        api_messages = [{"role": "system", "content": SYSTEM_PROMPT}] + messages

        response = client.chat.completions.create(model=MODEL, messages=api_messages, tools=tools)
        assistant_msg = response.choices[0].message

        msg_dict: dict = {"role": "assistant", "content": assistant_msg.content or ""}
        if assistant_msg.tool_calls:
            msg_dict["tool_calls"] = [
                {"id": tc.id, "type": "function", "function": {"name": tc.function.name, "arguments": tc.function.arguments}}
                for tc in assistant_msg.tool_calls
            ]
        messages.append(msg_dict)
        add_message(conn, session_id, msg_dict)

        if not assistant_msg.tool_calls:
            return {"final_response": assistant_msg.content, "messages": messages}

        for tool_call in assistant_msg.tool_calls:
            name = tool_call.function.name
            args = json.loads(tool_call.function.arguments)
            print(f"  🔧 {name}: {json.dumps(args, ensure_ascii=False)[:120]}")
            output = registry.dispatch(name, args)
            tool_msg = {"role": "tool", "tool_call_id": tool_call.id, "content": output}
            messages.append(tool_msg)
            add_message(conn, session_id, tool_msg)

    return {"final_response": "(max iterations reached)", "messages": messages}


# ---------------------------------------------------------------------------
# 入口
# ---------------------------------------------------------------------------

if __name__ == "__main__":
    print("=== s03: Session Store ===")
    print(f"Model: {MODEL} | DB: {DB_PATH}")

    conn = init_db(DB_PATH)
    session_id = create_session(conn)
    print(f"Session: {session_id}")
    print("Type 'quit' to exit, '/search <query>' to search history.\n")

    while True:
        user_input = input("You: ").strip()
        if not user_input or user_input.lower() in ("quit", "exit"):
            break

        if user_input.startswith("/search "):
            query = user_input[8:]
            results = search_sessions(conn, query)
            for r in results:
                print(f"  [{r['session_id'][:8]}] {r['snippet']}")
            print()
            continue

        result = run_conversation(user_input, conn, session_id)
        print(f"\nAssistant: {result['final_response']}\n")

    conn.close()

"""
s04: Prompt Builder — 多来源系统提示词组装

在 s03 基础上加入：
- 从 SOUL.md / MEMORY.md / 项目配置文件 动态组装 system prompt
- 缓存 system prompt（同一会话内不重新组装）
- 优先级链查找项目配置文件

运行:
    export OPENAI_API_KEY=sk-xxx
    python agents/s04_prompt_builder.py
"""

import json
import os
import sqlite3
import subprocess
import time
import uuid
from dataclasses import dataclass, field
from datetime import datetime
from pathlib import Path
from typing import Callable, Optional

from openai import OpenAI

# ---------------------------------------------------------------------------
# 配置
# ---------------------------------------------------------------------------

BASE_URL = os.getenv("OPENAI_BASE_URL", "https://openrouter.ai/api/v1")
API_KEY = os.getenv("OPENAI_API_KEY", "")
MODEL = os.getenv("MODEL", "anthropic/claude-sonnet-4")
MAX_ITERATIONS = int(os.getenv("MAX_ITERATIONS", "30"))
DB_PATH = os.getenv("DB_PATH", "state.db")
HERMES_HOME = Path(os.getenv("HERMES_HOME", Path.home() / ".hermes"))

client = OpenAI(base_url=BASE_URL, api_key=API_KEY)

# ---------------------------------------------------------------------------
# 工具注册表（复用 s02）
# ---------------------------------------------------------------------------


@dataclass
class ToolEntry:
    name: str
    toolset: str
    schema: dict
    handler: Callable
    is_async: bool = False
    requires_env: list = field(default_factory=list)
    check_fn: Optional[Callable] = None


class ToolRegistry:
    def __init__(self):
        self._tools: dict[str, ToolEntry] = {}

    def register(self, name, toolset, schema, handler, **kwargs):
        self._tools[name] = ToolEntry(name=name, toolset=toolset, schema=schema, handler=handler, **kwargs)

    def dispatch(self, name, args, **kwargs):
        entry = self._tools.get(name)
        if not entry:
            return json.dumps({"error": f"Unknown tool: {name}"})
        return entry.handler(args, **kwargs)

    def get_definitions(self, enabled_toolsets=None):
        defs = []
        for entry in self._tools.values():
            if enabled_toolsets and entry.toolset not in enabled_toolsets:
                continue
            defs.append({"type": "function", "function": entry.schema})
        return defs


registry = ToolRegistry()

# --- 工具实现 ---

def handle_terminal(args, **kwargs):
    command = args.get("command", "")
    for blocked in ["rm -rf /", "mkfs", "dd if=", "shutdown"]:
        if blocked in command:
            return json.dumps({"error": f"Blocked: {blocked}"})
    try:
        result = subprocess.run(command, shell=True, capture_output=True, text=True, timeout=30)
        output = result.stdout + result.stderr
        return output[:10000] if output else "(no output)"
    except subprocess.TimeoutExpired:
        return "(timed out)"
    except Exception as e:
        return f"(error: {e})"

registry.register("terminal", "terminal", {
    "name": "terminal", "description": "Run a shell command.",
    "parameters": {"type": "object", "properties": {"command": {"type": "string"}}, "required": ["command"]},
}, handle_terminal)

def handle_read_file(args, **kwargs):
    try:
        with open(args["path"], "r", encoding="utf-8") as f:
            return f.read(100_000) or "(empty)"
    except Exception as e:
        return f"(error: {e})"

registry.register("read_file", "file", {
    "name": "read_file", "description": "Read a file.",
    "parameters": {"type": "object", "properties": {"path": {"type": "string"}}, "required": ["path"]},
}, handle_read_file)

def handle_write_file(args, **kwargs):
    try:
        os.makedirs(os.path.dirname(args["path"]) or ".", exist_ok=True)
        with open(args["path"], "w", encoding="utf-8") as f:
            f.write(args["content"])
        return f"Written {len(args['content'])} chars"
    except Exception as e:
        return f"(error: {e})"

registry.register("write_file", "file", {
    "name": "write_file", "description": "Write content to a file.",
    "parameters": {"type": "object", "properties": {"path": {"type": "string"}, "content": {"type": "string"}}, "required": ["path", "content"]},
}, handle_write_file)

