def init_db(db_path):
    conn = sqlite3.connect(db_path)
    conn.execute("PRAGMA journal_mode=WAL")
    conn.executescript("""
        CREATE TABLE IF NOT EXISTS sessions (id TEXT PRIMARY KEY, source TEXT, model TEXT, started_at REAL);
        CREATE TABLE IF NOT EXISTS messages (id INTEGER PRIMARY KEY AUTOINCREMENT, session_id TEXT REFERENCES sessions(id), role TEXT, content TEXT, tool_calls TEXT, tool_call_id TEXT, timestamp REAL);
    """)
    return conn

def create_session(conn, source="cli"):
    sid = str(uuid.uuid4())
    conn.execute("INSERT INTO sessions VALUES (?,?,?,?)", (sid, source, MODEL, time.time()))
    conn.commit()
    return sid

def add_message(conn, session_id, msg):
    conn.execute("INSERT INTO messages (session_id,role,content,tool_calls,tool_call_id,timestamp) VALUES (?,?,?,?,?,?)",
        (session_id, msg["role"], msg.get("content",""), json.dumps(msg.get("tool_calls")) if msg.get("tool_calls") else None, msg.get("tool_call_id"), time.time()))
    conn.commit()

def get_session_messages(conn, session_id):
    rows = conn.execute("SELECT role,content,tool_calls,tool_call_id FROM messages WHERE session_id=? ORDER BY id", (session_id,)).fetchall()
    msgs = []
    for role, content, tc_json, tc_id in rows:
        m: dict = {"role": role, "content": content or ""}
        if tc_json: m["tool_calls"] = json.loads(tc_json)
        if tc_id: m["tool_call_id"] = tc_id
        msgs.append(m)
    return msgs

